window.PACTO.acts["reg-2010-439"]={"label": "REGOLAMENTO (UE) N. 439/2010 DEL PARLAMENTO EUROPEO E DEL CONSIGLIO", "short": "Reg. 439/2010", "file": "ext-reg-2010-439.html", "external": true, "version": "originale GU", "eurlex": "https://eur-lex.europa.eu/eli/reg/2010/439/oj/ita", "articles": {"1": {"label": "Articolo 1", "heading": "Istituzione dell’Ufficio europeo di sostegno per l’asilo", "anchor": "art_1", "frags": [[null, "<p class=\"oj-normal\">È istituito l’Ufficio europeo di sostegno per l’asilo («l'Ufficio di sostegno») al fine di contribuire a una migliore attuazione del sistema europeo comune di asilo («il CEAS»), a rafforzare la cooperazione pratica in materia di asilo fra gli Stati membri e a fornire o coordinare il sostegno operativo agli Stati membri i cui sistemi di asilo e accoglienza sono sottoposti a una pressione particolare.</p>"]]}, "2": {"label": "Articolo 2", "heading": "Finalità dell’Ufficio di sostegno", "anchor": "art_2", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L’Ufficio di sostegno facilita, coordina e rafforza la cooperazione pratica in materia di asilo fra gli Stati membri nei suoi molteplici aspetti e contribuisce a una migliore attuazione del sistema europeo comune di asilo. A questo riguardo, l'Ufficio di sostegno partecipa a pieno titolo alla dimensione esterna di tale sistema.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'Ufficio di sostegno fornisce un sostegno operativo efficace agli Stati membri i cui sistemi di asilo e accoglienza sono sottoposti ad una pressione particolare, facendo appello a tutte le risorse utili a sua disposizione, che possono includere il coordinamento delle risorse fornite dagli Stati membri alle condizioni previste dal presente regolamento.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L’Ufficio di sostegno presta assistenza scientifica e tecnica in relazione alle politiche e alla legislazione dell'Unione in tutti i settori che hanno ripercussioni dirette o indirette sull’asilo, così da apportare pieno sostegno alla cooperazione pratica nel settore e svolgere i suoi compiti in modo efficace. È una fonte indipendente di informazioni su tutte le questioni rientranti in tali ambiti.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   L’Ufficio di sostegno persegue la sua finalità in condizioni che gli consentono di svolgere un ruolo di riferimento grazie all’indipendenza e alla qualità scientifica e tecnica dell’assistenza prestata e delle informazioni diffuse, alla trasparenza delle sue procedure e delle modalità di funzionamento, alla diligenza nell’espletare i compiti attribuitigli e al supporto informatico necessario allo svolgimento del suo mandato.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   L’Ufficio di sostegno lavora a stretto contatto con le autorità degli Stati membri responsabili per l’asilo, con i servizi nazionali responsabili per l'immigrazione e l'asilo e con altri servizi nazionali, così come con la Commissione. L’Ufficio di sostegno svolge i propri compiti fermi restando quelli conferiti ad altri organismi pertinenti dell'Unione e lavora in stretta cooperazione con detti organismi e con l’UNHCR.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   L’Ufficio di sostegno non ha alcun potere in relazione al processo decisionale delle autorità degli Stati membri responsabili per l’asilo per quanto riguarda le singole domande di protezione internazionale.</p>\n</div>"]]}, "3": {"label": "Articolo 3", "heading": "Migliori prassi", "anchor": "art_3", "frags": [[null, "<p class=\"oj-normal\">L'Ufficio di sostegno organizza, promuove e coordina attività che consentano lo scambio di informazioni e l'individuazione e la condivisione delle migliori prassi fra gli Stati membri in materia di asilo.</p>"]]}, "4": {"label": "Articolo 4", "heading": "Informazioni sui paesi di origine", "anchor": "art_4", "frags": [[null, "<p class=\"oj-normal\">L'Ufficio di sostegno organizza, promuove e coordina attività relative alle informazioni sui paesi di origine, in particolare:</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la raccolta, secondo modalità trasparenti e imparziali, d'informazioni pertinenti, affidabili, accurate e aggiornate sui paesi di origine delle persone che fanno domanda di protezione internazionale, avvalendosi di ogni fonte pertinente, comprese le informazioni raccolte da organizzazioni governative e non governative e da organizzazioni internazionali, nonché da istituzioni e organismi dell'Unione;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l'elaborazione di relazioni sui paesi di origine, sulla base delle informazioni raccolte in conformità alla lettera a);</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la creazione e l'ulteriore sviluppo di un portale che raccolga le informazioni sui paesi di origine al fine di garantire la trasparenza in conformità delle regole necessarie per l'accesso a tali informazioni ai sensi dell'articolo 42;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l'elaborazione di un formato e di una metodologia comuni per la presentazione, la verifica e l'utilizzo delle informazioni sui paesi di origine;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l'analisi delle informazioni sui paesi di origine, condotta secondo modalità trasparenti nell'intento di promuovere la convergenza tra criteri di valutazione e, se del caso, utilizzando i risultati delle riunioni di uno o più gruppi di lavoro. Tale analisi non è volta a impartire istruzioni agli Stati membri sull'accoglimento o sulla reiezione delle domande di protezione internazionale.</p>\n</td>\n</tr>\n</tbody>\n</table>"]]}, "5": {"label": "Articolo 5", "heading": "Sostegno alla ricollocazione all'interno dell'Unione dei beneficiari di protezione internazionale", "anchor": "art_5", "frags": [[null, "<p class=\"oj-normal\">Per gli Stati membri i cui sistemi di asilo e accoglienza siano sottoposti a pressioni specifiche e sproporzionate, dovute specialmente alla loro situazione geografica o demografica, l'Ufficio di sostegno promuove, agevola e coordina gli scambi di informazioni e altre attività connesse alla ricollocazione all'interno dell'Unione. La ricollocazione all'interno dell'Unione è effettuata solo su base concordata tra gli Stati membri e con il consenso del beneficiario della protezione internazionale, nonché, se del caso, in consultazione con l'UNHCR.</p>"]]}, "6": {"label": "Articolo 6", "heading": "Sostegno alla formazione", "anchor": "art_6", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Ufficio di sostegno organizza e sviluppa la formazione destinata ai membri di tutte le amministrazioni e di tutti gli organismi giurisdizionali nazionali, e a qualsiasi tipo di servizio nazionale responsabile in materia di asilo negli Stati membri. La partecipazione alla formazione fa salvi i sistemi e le procedure nazionali.</p>\n<p class=\"oj-normal\">L'Ufficio di sostegno organizza tale formazione in stretta cooperazione con le autorità degli Stati membri responsabili per l'asilo e si avvale, ove necessario, della competenza di istituzioni accademiche e di altre organizzazioni pertinenti.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'Ufficio di sostegno gestisce ed elabora un curriculum europeo in materia di asilo tenuto conto della cooperazione dell'Unione esistente in tale settore.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   La formazione proposta dall'Ufficio di sostegno può essere generica, specifica o tematica e può includere la metodologia «formazione dei formatori».</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   La formazione specifica o tematica sulle conoscenze e competenze in materia di asilo includono e non si limitano a, in particolare:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">i diritti umani internazionali e l'<span class=\"oj-italic\">acquis</span> dell'Unione in materia di asilo, comprese specifiche problematiche giuridiche o giurisprudenziali;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le problematiche attinenti al trattamento delle domande di asilo di minori e di persone vulnerabili con esigenze particolari;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le tecniche di intervista;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l'utilizzo delle perizie mediche e legali nelle procedure di asilo;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le problematiche attinenti alla produzione e all'utilizzo delle informazioni sui paesi di origine;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le condizioni di accoglienza, compresa una speciale attenzione per i gruppi vulnerabili e le vittime di tortura.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Le azioni proposte sono di alta qualità e definiscono principi chiave e migliori prassi ai fini di una maggiore convergenza delle prassi e delle decisioni amministrative e della prassi giuridica, nel pieno rispetto dell'indipendenza degli organi giudiziari nazionali.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Per gli esperti che fanno parte del gruppo d'intervento in materia di asilo di cui all'articolo 15, l'Ufficio di sostegno offre una formazione specializzata attinente ai loro compiti e alle loro funzioni e organizza esercitazioni periodiche secondo un calendario di formazione specializzata ed esercitazioni indicato nel suo programma di lavoro annuale.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   L'Ufficio di sostegno può organizzare attività di formazione in cooperazione con gli Stati membri sul loro territorio.</p>\n</div>"]]}, "7": {"label": "Articolo 7", "heading": "Sostegno alla dimensione esterna del sistema europeo comune di asilo", "anchor": "art_7", "frags": [[null, "<p class=\"oj-normal\">In accordo con la Commissione, l'Ufficio di sostegno coordina gli scambi di informazioni e le altre azioni intraprese relativamente alle questioni attinenti all'attuazione degli strumenti e dei meccanismi relativi alla dimensione esterna del sistema europeo comune di asilo.</p>"], [null, "<p class=\"oj-normal\">L'Ufficio di sostegno coordina gli scambi di informazioni e altre azioni relativamente al reinsediamento intraprese dagli Stati membri con l'obiettivo di far fronte alle esigenze di protezione internazionale dei rifugiati nei paesi terzi e di dar prova di solidarietà ai paesi di accoglienza.</p>"], [null, "<p class=\"oj-normal\">Nell'ambito del suo mandato e conformemente all'articolo 49, l'Ufficio di sostegno può cooperare con le autorità competenti dei paesi terzi su aspetti tecnici, in particolare nell'intento di promuovere ed assistere il rafforzamento delle capacità nell'ambito dei sistemi di asilo ed accoglienza di tali paesi terzi, nonché di attuare programmi di protezione regionale e altre azioni pertinenti in grado di fornire soluzioni durature.</p>"]]}, "8": {"label": "Articolo 8", "heading": "Pressione particolare sui sistemi di asilo e accoglienza", "anchor": "art_8", "frags": [[null, "<p class=\"oj-normal\">L'Ufficio di sostegno coordina e appoggia ogni azione comune volta ad assistere i sistemi di asilo e accoglienza degli Stati membri sottoposti ad una pressione particolare che comporta un onere eccezionale ed urgente per le loro strutture di accoglienza e per i loro sistemi di asilo. Tale pressione può derivare dall'arrivo improvviso di un vasto numero di cittadini di paesi terzi che possono aver bisogno di protezione internazionale e dalla situazione geografica o demografica dello Stato membro.</p>"]]}, "9": {"label": "Articolo 9", "heading": "Raccolta e analisi di informazioni", "anchor": "art_9", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Onde poter valutare le esigenze degli Stati membri sottoposti a una pressione particolare, l'Ufficio di sostegno raccoglie, in particolare sulla base delle informazioni fornite dagli Stati membri, dall'UNHCR e, se del caso, da altre organizzazioni pertinenti, ogni informazione utile a individuare, preparare e definire le misure d'urgenza di cui all'articolo 10 per fronteggiare tale pressione.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'Ufficio di sostegno individua, raccoglie ed esamina sistematicamente, in base ai dati forniti dagli Stati membri sottoposti a una pressione particolare, informazioni sulle strutture e il personale disponibili, segnatamente in materia di traduzione ed interpretazione, informazioni sui paesi di origine e sull'assistenza nel trattamento e nella gestione dei singoli casi, nonché la capacità di accoglienza nei suddetti Stati membri sottoposti ad una pressione particolare, per favorire un rapido ed affidabile scambio di informazioni fra le varie autorità degli Stati membri responsabili per l'asilo.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L'Ufficio di sostegno analizza i dati relativi ad ogni arrivo improvviso di un vasto numero di cittadini di paesi terzi che possa determinare una pressione particolare sui sistemi di asilo e accoglienza ed assicura un rapido scambio di informazioni pertinenti tra gli Stati membri e la Commissione. L'Ufficio di sostegno utilizza i sistemi e i meccanismi di allarme rapido esistenti e, se del caso, istituisce un sistema di allarme rapido per fini propri.</p>\n</div>"]]}, "10": {"label": "Articolo 10", "heading": "Azioni di sostegno agli Stati membri", "anchor": "art_10", "frags": [[null, "<p class=\"oj-normal\">Su richiesta degli Stati membri interessati, l'Ufficio di sostegno coordina le azioni di sostegno agli Stati membri i cui sistemi di asilo e accoglienza sono sottoposti a una particolare pressione, in particolare coordinando:</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le azioni a vantaggio degli Stati membri sottoposti a una particolare pressione per rendere più agevole l'inizio dell'esame delle domande di asilo da parte delle autorità nazionali competenti;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le azioni dirette ad assicurare che gli Stati membri sottoposti a una particolare pressione possano mettere a disposizione adeguate strutture di accoglienza, in particolare alloggi d'emergenza, mezzi di trasporto e assistenza medica;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le squadre di sostegno per l'asilo, le cui modalità di funzionamento sono stabilite al capo 3.</p>\n</td>\n</tr>\n</tbody>\n</table>"]]}, "11": {"label": "Articolo 11", "heading": "Raccolta e scambio di informazioni", "anchor": "art_11", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Ufficio di sostegno organizza, coordina e promuove lo scambio di informazioni fra le autorità degli Stati membri responsabili per l’asilo e fra la Commissione e le autorità degli Stati membri responsabili per l’asilo per quanto riguarda l'attuazione dell'insieme degli strumenti rientranti nell'<span class=\"oj-italic\">acquis</span> dell'Unione in materia di asilo. A tal fine l'Ufficio di sostegno può creare banche dati fattuali, giuridiche e giurisprudenziali riguardanti gli strumenti relativi all'asilo a livello nazionale, dell'Unione e internazionale, utilizzando, fra l'altro, i dispositivi esistenti. Fatte salve le attività dell'Ufficio di sostegno ai sensi degli articoli 15 e 16, in tali banche dati non vengono memorizzati dati personali, a meno che l'Ufficio di sostegno non li abbia tratti da documenti accessibili al pubblico.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'Ufficio di sostegno raccoglie in particolare informazioni:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sul trattamento delle domande di protezione internazionale presso le amministrazioni e autorità nazionali;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sul diritto e gli sviluppi giuridici nazionali in materia di asilo, compresa la giurisprudenza.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"]]}, "12": {"label": "Articolo 12", "heading": "Relazioni e altri documenti dell'Ufficio di sostegno", "anchor": "art_12", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Ufficio di sostegno elabora una relazione annuale sulla situazione riguardante l'asilo nell'Unione, tenendo in debita considerazione le informazioni già rese disponibili da altre fonti pertinenti. In tale relazione l'Ufficio di sostegno valuta i risultati delle azioni svolte ai sensi del presente regolamento e ne fa un'analisi comparativa globale al fine di rafforzare la qualità, la coerenza e l'efficacia del sistema europeo comune di asilo.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   In conformità del suo programma di lavoro o su richiesta del consiglio di amministrazione o della Commissione, tenendo in debita considerazione i pareri espressi dagli Stati membri o dal Parlamento europeo e operando in stretta consultazione con i suoi gruppi di lavoro e la Commissione, l'Ufficio di sostegno può adottare documenti tecnici riguardanti l'attuazione degli strumenti dell'Unione in materia di asilo, quali in particolare orientamenti e manuali operativi. Quando tali documenti tecnici fanno riferimento ad elementi del diritto internazionale dei rifugiati, si tiene debito conto dei pertinenti orientamenti dell'UNHCR. Tali documenti non hanno l'intento di dare istruzioni agli Stati membri sull'accoglimento o sulla reiezione delle domande di protezione internazionale.</p>\n</div>"]]}, "13": {"label": "Articolo 13", "heading": "Coordinamento", "anchor": "art_13", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Lo Stato membro o gli Stati membri sottoposti a una particolare pressione possono chiedere che l'Ufficio di sostegno provveda all'invio di una squadra di sostegno per l'asilo. Lo Stato membro o gli Stati membri richiedenti forniscono, in particolare, una descrizione della situazione, indicano gli obiettivi della richiesta di invio e specificano il proprio previsto fabbisogno, in conformità dell'articolo 18, paragrafo 1.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   In risposta a tale richiesta, l'Ufficio di sostegno può coordinare l'assistenza operativa e tecnica necessaria per lo Stato membro o gli Stati membri richiedenti e per l'invio, per un periodo di tempo limitato, di una squadra di sostegno per l'asilo sul territorio di tale Stato membro o di tali Stati membri sulla base del piano operativo di cui all'articolo 18.</p>\n</div>"]]}, "14": {"label": "Articolo 14", "heading": "Assistenza tecnica", "anchor": "art_14", "frags": [[null, "<p class=\"oj-normal\">Le squadre di sostegno per l’asilo apportano la propria competenza, come convenuto nel piano operativo di cui all'articolo 18, in particolare in relazione ai servizi di interpretazione, alle informazioni sui paesi d’origine e alla conoscenza del trattamento e della gestione dei fascicoli di asilo, nel quadro delle azioni di sostegno agli Stati membri di cui all’articolo 10.</p>"]]}, "15": {"label": "Articolo 15", "heading": "Gruppo d'intervento in materia di asilo", "anchor": "art_15", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Su proposta del direttore esecutivo, il consiglio di amministrazione decide a maggioranza dei tre quarti dei suoi membri aventi diritto di voto sui profili e sul numero totale di esperti da mettere a disposizione per la costituzione delle squadre di sostegno per l’asilo (gruppo d'intervento in materia di asilo). Nell'ambito del gruppo d'intervento in materia di asilo, l'Ufficio di sostegno stabilisce un elenco di interpreti. La stessa procedura si applica per eventuali successive modifiche dei profili e del numero totale degli esperti del gruppo.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli Stati membri contribuiscono al gruppo d'intervento in materia di asilo tramite un gruppo di esperti nazionali costituito in base ai diversi profili, designando gli esperti corrispondenti ai profili richiesti.</p>\n<p class=\"oj-normal\">Gli Stati membri assistono l'Ufficio di sostegno nell'individuazione degli interpreti da inserire nell'elenco di interpreti.</p>\n<p class=\"oj-normal\">Gli Stati membri possono scegliere di inviare interpreti o di metterli a disposizione tramite videoconferenza.</p>\n</div>"]]}, "16": {"label": "Articolo 16", "heading": "Invio delle squadre di sostegno per l'asilo", "anchor": "art_16", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Lo Stato membro di origine conserva la propria autonomia per quanto riguarda la selezione del numero e dei profili degli esperti (gruppo nazionale) e la durata della missione. Gli Stati membri mettono a disposizione tali esperti su richiesta dell’Ufficio di sostegno, a meno che si trovino a far fronte a una situazione che incida in misura sostanziale sull’adempimento dei compiti nazionali, come per esempio nel caso di una carenza d'organico per l'espletamento delle procedure di determinazione dello status delle persone che chiedono la protezione internazionale. Gli Stati membri comunicano quanto prima, su richiesta dell’Ufficio di sostegno, il numero, i nomi e i profili degli esperti del loro gruppo nazionale che possono mettere a disposizione entro il più breve tempo possibile per far parte di una squadra di sostegno.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Nel determinare la composizione di una squadra di sostegno per l’asilo, il direttore esecutivo tiene conto delle circostanze particolari in cui versa lo Stato membro richiedente. La squadra di sostegno è costituita secondo il piano operativo elaborato a norma dell’articolo 18.</p>\n</div>"]]}, "17": {"label": "Articolo 17", "heading": "Procedura di decisione dell'invio", "anchor": "art_17", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Se necessario, il direttore esecutivo può inviare esperti dell’Ufficio di sostegno per valutare la situazione dello Stato membro richiedente.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il direttore esecutivo informa immediatamente il consiglio di amministrazione di ogni richiesta di invio delle squadre di sostegno.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il direttore esecutivo decide in merito alla richiesta di invio delle squadre di sostegno per l'asilo quanto prima e al più tardi entro cinque giorni lavorativi dalla data di ricevimento della richiesta. Il direttore esecutivo comunica per iscritto la decisione contemporaneamente allo Stato membro richiedente e al consiglio di amministrazione, precisandone le motivazioni principali.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Se il direttore esecutivo decide di inviare una o più squadre di sostegno per l’asilo, l’Ufficio di sostegno e lo Stato membro richiedente elaborano immediatamente un piano operativo a norma dell’articolo 18.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Subito dopo l’approvazione del piano operativo, il direttore esecutivo informa gli Stati membri in merito al numero e ai profili richiesti degli esperti che parteciperanno alle squadre di sostegno. Queste informazioni sono fornite per iscritto ai referenti nazionali di cui all’articolo 19 e menzionano la data di invio prevista. Agli stessi viene trasmessa anche una copia del piano operativo.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   In caso di assenza o di impedimento del direttore esecutivo, le decisioni relative all’invio delle squadre di sostegno per l’asilo sono prese dal capo unità che lo sostituisce.</p>\n</div>"]]}, "18": {"label": "Articolo 18", "heading": "Piano operativo", "anchor": "art_18", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il direttore esecutivo e lo Stato membro richiedente concordano un piano operativo che definisca nel dettaglio le condizioni per l’invio delle squadre di sostegno per l’asilo. Il piano operativo include:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">una descrizione della situazione, con <span class=\"oj-italic\">modus operandi</span> e obiettivi dell’invio, obiettivi operativi compresi;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la durata prevista della missione delle squadre di sostegno;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l’area geografica di competenza nello Stato membro richiedente in cui le squadre di sostegno saranno inviate;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">una descrizione dei compiti e le istruzioni specifiche per i membri delle squadre di sostegno, anche in merito alle banche dati che sono autorizzati a consultare e all'equipaggiamento che possono utilizzare nello Stato membro richiedente; e</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la composizione delle squadre di sostegno.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Per qualsiasi modifica o adattamento del piano operativo è necessario il consenso congiunto del direttore esecutivo e dello Stato membro richiedente. L’Ufficio di sostegno trasmette immediatamente agli Stati membri partecipanti una copia del piano operativo modificato o adattato.</p>\n</div>"]]}, "19": {"label": "Articolo 19", "heading": "Referente nazionale", "anchor": "art_19", "frags": [[null, "<p class=\"oj-normal\">Ciascuno Stato membro designa un referente nazionale incaricato di comunicare con l’Ufficio di sostegno per tutte le questioni relative alle squadre di sostegno per l’asilo.</p>"]]}, "20": {"label": "Articolo 20", "heading": "Referente dell'Unione", "anchor": "art_20", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il direttore esecutivo designa uno o più esperti dell’Ufficio di sostegno quali referenti dell'Unione incaricati del coordinamento e ne informa lo Stato membro ospitante.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il referente dell'Unione agisce a nome dell’Ufficio di sostegno per tutti gli aspetti relativi all’invio delle squadre di sostegno per l’asilo, In particolare, il referente dell'Unione:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">funge da interfaccia tra l’Ufficio di sostegno e lo Stato membro ospitante;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">funge da interfaccia tra l’Ufficio di sostegno e i membri delle squadre di sostegno per l'asilo, fornendo assistenza, per conto dell’Ufficio di sostegno, su tutte le questioni connesse con le condizioni dell'invio di tali squadre;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">controlla la corretta attuazione del piano operativo; e</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">riferisce all’Ufficio di sostegno su tutti gli aspetti dell’invio delle squadre di sostegno per l'asilo.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il direttore esecutivo può autorizzare i referenti dell'Unione a contribuire alla risoluzione di qualsiasi controversia sull’attuazione del piano operativo e sull’invio delle squadre di sostegno per l’asilo.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Nell’esecuzione dei suoi compiti, il referente dell'Unione riceve istruzioni soltanto dall’Ufficio di sostegno.</p>\n</div>"]]}, "21": {"label": "Articolo 21", "heading": "Responsabilità civile", "anchor": "art_21", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Quando i membri di una squadra di sostegno per l’asilo operano in uno Stato membro ospitante, tale Stato membro è responsabile dei danni eventuali da loro causati durante le loro operazioni, conformemente alla sua legislazione nazionale.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Ove tali danni siano causati da negligenza grave o comportamento doloso, lo Stato membro ospitante può rivolgersi allo Stato membro di origine per ottenere da quest’ultimo il rimborso di eventuali risarcimenti erogati alle vittime o agli aventi diritto.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Fatto salvo l’esercizio dei suoi diritti nei confronti di terzi, ciascuno Stato membro rinuncia a chiedere allo Stato membro di origine o a qualsiasi altro Stato membro il risarcimento dei danni subiti, a meno che il danno non sia dovuto a negligenza grave o comportamento doloso.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Eventuali controversie tra Stati membri sull’applicazione dei paragrafi 2 e 3 del presente articolo che tali Stati non possano risolvere mediante negoziati sono da essi deferite alla Corte di giustizia ai sensi dell’articolo 273 del TFUE.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Fatto salvo l'esercizio dei suoi diritti nei confronti di terzi, l'Ufficio di sostegno sostiene le spese connesse con i danni causati all'equipaggiamento dell'Ufficio di sostegno durante la missione, a meno che il danno non sia dovuto a negligenza grave o comportamento doloso.</p>\n</div>"]]}, "22": {"label": "Articolo 22", "heading": "Responsabilità penale", "anchor": "art_22", "frags": [[null, "<p class=\"oj-normal\">Durante la missione di una squadra di sostegno per l’asilo, i membri della squadra di sostegno per l’asilo sono assimilati ai funzionari dello Stato membro ospitante per quanto riguarda i reati che commettano o di cui siano vittime.</p>"]]}, "23": {"label": "Articolo 23", "heading": "Costi", "anchor": "art_23", "frags": [[null, "<p class=\"oj-normal\">Quando gli Stati membri mettono a disposizione i loro esperti per l’invio delle squadre di sostegno per l’asilo, l’Ufficio di sostegno copre i seguenti costi:</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">viaggio dallo Stato membro di origine allo Stato membro ospitante e dallo Stato membro ospitante allo Stato membro di origine;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">vaccinazione;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">assicurazioni specifiche richieste;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">assistenza sanitaria;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">diaria, compreso l'alloggio;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">attrezzature tecniche dell’Ufficio di sostegno; e</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">onorari degli esperti.</p>\n</td>\n</tr>\n</tbody>\n</table>"]]}, "24": {"label": "Articolo 24", "heading": "Struttura amministrativa e di gestione dell’Ufficio di sostegno", "anchor": "art_24", "frags": [[null, "<p class=\"oj-normal\">La struttura amministrativa e di gestione dell’Ufficio di sostegno comprende:</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">un consiglio di amministrazione;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">un direttore esecutivo e il personale dell’Ufficio di sostegno.</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<p class=\"oj-normal\">La struttura amministrativa e di gestione dell’Ufficio di sostegno può comprendere un comitato esecutivo, se istituito in conformità dell'articolo 29, paragrafo 2.</p>"]]}, "25": {"label": "Articolo 25", "heading": "Composizione del consiglio di amministrazione", "anchor": "art_25", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il consiglio di amministrazione si compone di un membro nominato da ciascuno Stato membro vincolato dal presente regolamento e di due membri nominati dalla Commissione.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Ogni membro del consiglio di amministrazione può essere rappresentato o accompagnato da un supplente. Quando accompagna un membro del consiglio di amministrazione, il supplente assiste senza diritto di voto.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   I membri del consiglio di amministrazione sono nominati in base all'esperienza, alla responsabilità professionale e all'alto livello di competenza nel settore dell’asilo.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Un rappresentante dell'UNHCR è membro del consiglio di amministrazione senza diritto di voto.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Il mandato dei membri del consiglio di amministrazione è di tre anni. Tale mandato è rinnovabile. Allo scadere del mandato o in caso di dimissioni i membri restano in carica fino al rinnovo del mandato o fino alla loro sostituzione.</p>\n</div>"]]}, "26": {"label": "Articolo 26", "heading": "Presidenza del consiglio di amministrazione", "anchor": "art_26", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il consiglio di amministrazione elegge un presidente e un vicepresidente scegliendoli tra i suoi membri con diritto di voto. Il vicepresidente sostituisce ex officio il presidente quando quest’ultimo è impossibilitato a svolgere le proprie funzioni.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il presidente e il vicepresidente hanno un mandato di tre anni rinnovabile un’unica volta. Tuttavia, se cessano di far parte del consiglio di amministrazione in un qualsiasi momento del mandato da presidente o vicepresidente, questo termina automaticamente alla stessa data.</p>\n</div>"]]}, "27": {"label": "Articolo 27", "heading": "Riunioni del consiglio di amministrazione", "anchor": "art_27", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Le riunioni del consiglio di amministrazione vengono indette dal presidente. Il direttore esecutivo partecipa alle riunioni. Il rappresentante dell'UNHCR non partecipa alle riunioni quando il consiglio di amministrazione svolge le funzioni di cui all'articolo 29, paragrafo 1, lettere b), h), i), j) e m), e all'articolo 29, paragrafo 2, e quando il consiglio di amministrazione mette a disposizione risorse finanziarie per finanziare azioni che consentono all'Ufficio di sostegno di beneficiare dell'esperienza e della competenza in materia di asilo dell'UNHCR come previsto all'articolo 50.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il consiglio di amministrazione tiene almeno due riunioni ordinarie all'anno. Si riunisce inoltre su istanza del presidente o su richiesta di almeno un terzo dei suoi membri.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il consiglio di amministrazione può invitare a partecipare alle sue riunioni, in veste di osservatore, ogni persona il cui parere possa essere rilevante.</p>\n<p class=\"oj-normal\">La Danimarca è invitata a partecipare alle riunioni del consiglio di amministrazione.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   I membri del consiglio di amministrazione, fatte salve le disposizioni del suo regolamento interno, possono farsi assistere da consulenti o esperti.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   L'Ufficio di sostegno provvede alle funzioni di segreteria del consiglio di amministrazione.</p>\n</div>"]]}, "28": {"label": "Articolo 28", "heading": "Modalità di votazione", "anchor": "art_28", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Salvo disposizioni contrarie, il consiglio di amministrazione decide a maggioranza assoluta dei membri aventi diritto di voto. Ogni membro avente tale diritto dispone di un voto. In assenza di un membro, il supplente è abilitato a esercitare il suo diritto di voto.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il direttore esecutivo non partecipa al voto.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il presidente partecipa al voto.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Gli Stati membri che non partecipano all’integralità dell’<span class=\"oj-italic\">acquis</span> dell'Unione in materia di asilo non prendono parte al voto qualora il consiglio di amministrazione debba prendere decisioni di cui all'articolo 29, paragrafo 1, lettera e), e il documento tecnico in questione riguardi esclusivamente uno strumento dell'Unione in materia di asilo da cui non sono vincolati.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Il regolamento interno del consiglio di amministrazione stabilisce le regole dettagliate concernenti la votazione, in particolare le circostanze in cui un membro può agire per conto di un altro, e i requisiti di quorum, ove necessario.</p>\n</div>"]]}, "29": {"label": "Articolo 29", "heading": "Funzioni del consiglio di amministrazione", "anchor": "art_29", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il consiglio di amministrazione provvede affinché l’Ufficio di sostegno esegua i compiti ad esso affidati. È l’organo di programmazione e di controllo dell’Ufficio di sostegno e svolge in particolare le seguenti mansioni:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta il proprio regolamento interno, a maggioranza dei tre quarti dei membri aventi diritto di voto e previo parere della Commissione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">nomina il direttore esecutivo in conformità dell’articolo 30, esercita potere disciplinare nei confronti di quest’ultimo e, se necessario, lo sospende o lo revoca;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta una relazione generale annuale sulle attività dell’Ufficio di sostegno e la trasmette, entro il 15 giugno dell’anno successivo, al Parlamento europeo, al Consiglio, alla Commissione e alla Corte dei conti. La relazione generale annuale è pubblica;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta una relazione annuale sulla situazione riguardante l'asilo nell'Unione in conformità dell'articolo 12, paragrafo 1. Tale relazione è presentata al Parlamento europeo. Il Consiglio e la Commissione possono chiedere che la relazione sia presentata anche a loro;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta i documenti tecnici di cui all'articolo 12, paragrafo 2;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">entro il 30 settembre di ogni anno, in base a un progetto presentato dal direttore esecutivo e previo parere della Commissione, adotta a maggioranza di tre quarti dei suoi membri aventi diritto di voto il programma di lavoro dell'Ufficio di sostegno per l'anno successivo e lo trasmette al Parlamento europeo, al Consiglio e alla Commissione. Tale programma di lavoro è adottato secondo la procedura annuale di bilancio dell'Unione e il programma di lavoro legislativo dell'Unione nell'ambito dell’asilo;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">svolge le sue funzioni riguardanti il bilancio dell'Ufficio di sostegno a norma del capo 5;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">h)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">stabilisce le modalità pratiche di applicazione del regolamento (CE) n. 1049/2001 conformemente all’articolo 42 del presente regolamento;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta la politica relativa al personale dell'Ufficio di sostegno conformemente all’articolo 38;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">j)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta, dopo aver chiesto il parere della Commissione, il piano pluriennale in materia di politica del personale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">k)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">prende tutte le decisioni ai fini dell’attuazione del mandato dell’Ufficio di sostegno quale definito dal presente regolamento;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">l)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">prende tutte le decisioni relative alla creazione e, se necessario, allo sviluppo dei sistemi informativi previsti dal presente regolamento, fra cui il portale di informazioni di cui all’articolo 4, lettera c); e</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">m)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">prende ogni decisione relativa alla creazione e, se necessario, alla modifica delle strutture interne dell’Ufficio di sostegno.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il consiglio di amministrazione può istituire un comitato esecutivo per assistere il consiglio stesso e il direttore esecutivo nel predisporre decisioni, programmi di lavoro e attività che dovranno essere adottati dal consiglio di amministrazione e quando necessario, in considerazione dell'urgenza, per prendere decisioni provvisorie a nome del consiglio di amministrazione.</p>\n<p class=\"oj-normal\">Tale comitato esecutivo è composto di otto membri nominati fra i membri del consiglio di amministrazione tra i quali figura uno dei membri della Commissione all'interno del consiglio di amministrazione. Il mandato dei membri del comitato esecutivo è di durata pari al mandato dei membri del consiglio di amministrazione.</p>\n<p class=\"oj-normal\">Su richiesta del comitato esecutivo, i rappresentanti dell'UNHCR o qualsiasi altra persona il cui parere possa essere rilevante possono partecipare alle riunioni del comitato esecutivo senza diritto di voto.</p>\n<p class=\"oj-normal\">L'Ufficio di sostegno stabilisce le modalità di funzionamento del comitato esecutivo nel regolamento interno dell'Ufficio di sostegno e le rende pubbliche.</p>\n</div>"]]}, "30": {"label": "Articolo 30", "heading": "Nomina del direttore esecutivo", "anchor": "art_30", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il direttore esecutivo è nominato dal consiglio di amministrazione, per un periodo di cinque anni, tra i candidati idonei selezionati tramite un concorso generale organizzato dalla Commissione. La procedura di selezione prevede la pubblicazione nella Gazzetta ufficiale dell'Unione europea e in altri strumenti d'informazione di un invito a manifestare interesse. Il consiglio di amministrazione può richiedere l'organizzazione di una nuova procedura se non ritiene soddisfacente l'idoneità dei candidati inclusi nel primo elenco. Il direttore esecutivo è nominato in base ai suoi meriti personali, alla sua esperienza in materia di asilo e alle sue capacità di direzione e gestione. Prima della nomina, il candidato prescelto dal consiglio di amministrazione è invitato a rendere una dichiarazione dinanzi alla o alle commissioni competenti del Parlamento europeo e a rispondere alle domande dei membri di tali commissioni.</p>\n<p class=\"oj-normal\">Dopo detta dichiarazione il Parlamento europeo può adottare un parere nel quale espone la sua opinione sul candidato selezionato. Il consiglio di amministrazione informa il Parlamento europeo sul modo in cui tale parere è stato preso in considerazione. Il parere è trattato in modo personale e riservato fino alla nomina del candidato.</p>\n<p class=\"oj-normal\">Nel corso degli ultimi nove mesi del mandato quinquennale del direttore esecutivo, la Commissione procede a una valutazione che riguarda in particolare:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">—</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">i risultati ottenuti dal direttore esecutivo; nonché</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">—</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">i compiti e le necessità dell’Ufficio di sostegno per gli anni successivi.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il consiglio di amministrazione, tenuto conto di tale valutazione, può prorogare una volta il mandato del direttore esecutivo per un massimo di tre anni, ma solo quando tale proroga sia giustificata dai compiti e dalle necessità dell’Ufficio di sostegno.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il consiglio di amministrazione informa il Parlamento europeo dell'intenzione di prorogare il mandato del direttore esecutivo. Nel mese precedente tale proroga, il direttore esecutivo è invitato a rendere una dichiarazione dinanzi alla o alle commissioni competenti del Parlamento europeo e a rispondere alle domande dei membri di tali commissioni.</p>\n</div>"]]}, "31": {"label": "Articolo 31", "heading": "Funzioni del direttore esecutivo", "anchor": "art_31", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Ufficio di sostegno è diretto dal suo direttore esecutivo, che è indipendente nell'espletamento delle sue funzioni. Il direttore esecutivo risponde delle sue attività al consiglio di amministrazione.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Fatte salve le competenze della Commissione, del consiglio di amministrazione o del comitato esecutivo, se istituito, il direttore esecutivo non sollecita né accetta istruzioni da alcun governo o altro organismo.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Su richiesta, il direttore esecutivo riferisce al Parlamento europeo sull'esercizio delle sue funzioni. Il Consiglio può invitare il direttore esecutivo a presentare una relazione sull'esercizio delle sue funzioni.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il direttore esecutivo è il rappresentante legale dell’Ufficio di sostegno.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Il direttore esecutivo può essere assistito da uno o più capi unità. In caso di sua assenza o di impedimento, un capo unità lo sostituisce.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Il direttore esecutivo è responsabile della gestione amministrativa dell'Ufficio di sostegno e dell'espletamento delle funzioni affidategli dal presente regolamento. In particolare il direttore esecutivo è responsabile per:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la gestione corrente dell’Ufficio di sostegno;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l'elaborazione di programmi di lavoro per l’Ufficio di sostegno, previo parere della Commissione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l'attuazione delle decisioni e dei programmi di lavoro adottati dal consiglio di amministrazione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l'elaborazione delle relazioni sui paesi d’origine di cui all’articolo 4, lettera b);</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la predisposizione del progetto di regolamento finanziario dell’Ufficio di sostegno, al fine della sua adozione da parte del consiglio di amministrazione ai sensi dell’articolo 37, e delle sue misure d’esecuzione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la predisposizione del progetto di stato di previsione delle entrate e delle spese dell’Ufficio di sostegno e dell’esecuzione del bilancio;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l'esercizio delle competenze di cui all’articolo 38 nei confronti del personale dell’Ufficio di sostegno;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">h)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l'adozione di tutte le decisioni relative alla gestione dei sistemi informativi previsti dal presente regolamento, fra cui il portale d’informazioni di cui all’articolo 4, lettera c);</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l'adozione di ogni decisione riguardante la gestione delle strutture amministrative interne dell’Ufficio di sostegno; e</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">j)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il coordinamento e il funzionamento del forum consultivo di cui all'articolo 51. A tal fine il direttore esecutivo, in consultazione con le pertinenti organizzazioni della società civile, adotta innanzi tutto un piano per l'insediamento del forum consultivo. Una volta formalmente insediato, il direttore esecutivo, in consultazione con il forum consultivo, adotta un piano operativo che comprende norme sulla frequenza e la natura della consultazione e i meccanismi organizzativi per l'attuazione dell'articolo 51. Sono inoltre convenuti criteri trasparenti per la partecipazione continuativa al forum consultivo.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"]]}, "32": {"label": "Articolo 32", "heading": "Gruppi di lavoro", "anchor": "art_32", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Nell’ambito del suo mandato, quale definito nel presente regolamento, l’Ufficio di sostegno può costituire gruppi di lavoro composti da esperti delle autorità competenti degli Stati membri attive nel settore dell’asilo, compresi gli organismi giudiziari. L'Ufficio di sostegno costituisce gruppi di lavoro ai fini dell'articolo 4, lettera e), e dell'articolo 12, paragrafo 2. Gli esperti possono essere sostituiti da supplenti, nominati contestualmente.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   La Commissione partecipa di diritto ai gruppi di lavoro. I rappresentanti dell’UNHCR possono presenziare alle riunioni dei gruppi di lavoro dell’Ufficio di sostegno, integralmente o in parte a seconda del carattere delle questioni affrontate.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   I gruppi di lavoro possono invitare a partecipare alle riunioni ogni persona il cui parere possa essere rilevante, in particolare rappresentanti delle organizzazioni della società civile operanti nel settore dell’asilo.</p>\n</div>"]]}, "33": {"label": "Articolo 33", "heading": "Bilancio", "anchor": "art_33", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Tutte le entrate e le spese dell'Ufficio di sostegno sono oggetto di previsioni per ciascun esercizio finanziario, che coincide con l'anno civile, e sono iscritte nel bilancio dell'Ufficio di sostegno.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Le entrate e le spese iscritte nel bilancio dell'Ufficio di sostegno devono essere in pareggio.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Fatte salve altre risorse, le entrate dell’Ufficio di sostegno comprendono:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">un contributo dell'Unione iscritto al bilancio generale dell'Unione europea;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">eventuali contributi volontari degli Stati membri;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">i diritti percepiti per pubblicazioni o qualsiasi altro servizio fornito dall’Ufficio di sostegno;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">un contributo dei paesi associati.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Le spese dell'Ufficio di sostegno comprendono le retribuzioni del personale, le spese amministrative e di infrastruttura, le spese di esercizio.</p>\n</div>"]]}, "34": {"label": "Articolo 34", "heading": "Stesura del bilancio", "anchor": "art_34", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Ogni anno il direttore esecutivo predispone un progetto di stato di previsione delle entrate e delle spese dell’Ufficio di sostegno insieme per l’esercizio finanziario successivo, che comprende la tabella dell’organico, e lo trasmette al consiglio di amministrazione.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Sulla base di tale progetto, il consiglio di amministrazione prepara uno stato di previsione provvisorio delle entrate e delle spese dell’Ufficio di sostegno per l’esercizio finanziario successivo.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il progetto di stato di previsione provvisorio delle entrate e delle spese dell’Ufficio di sostegno è trasmesso alla Commissione entro il 10 febbraio di ogni anno. Entro il 31 marzo il consiglio di amministrazione invia alla Commissione lo stato di previsione definitivo, che include un progetto di tabella dell’organico.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   La Commissione trasmette al Parlamento europeo e al Consiglio («l'autorità di bilancio») lo stato di previsione con il progetto di bilancio generale dell'Unione europea.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Sulla base di tale stato di previsione, la Commissione inserisce nel progetto di bilancio generale dell'Unione europea le previsioni ritenute necessarie per la tabella dell'organico nonché l'importo della sovvenzione da iscrivere al bilancio generale, che sottopone all'autorità di bilancio a norma degli articoli 313 e 314 del TFUE.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   L'autorità di bilancio autorizza gli stanziamenti a titolo della sovvenzione destinata all'Ufficio di sostegno.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   L'autorità di bilancio adotta la tabella dell'organico dell’Ufficio di sostegno.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   Il consiglio di amministrazione adotta il bilancio dell'Ufficio di sostegno. Esso diventa definitivo dopo l’adozione definitiva del bilancio generale dell’Unione europea. Se del caso, si procede agli opportuni adeguamenti.</p>\n</div>"], [9, "<div>\n<p class=\"oj-normal\">9.   Il consiglio di amministrazione comunica al più presto all’autorità di bilancio l’intenzione di realizzare qualsiasi progetto che possa avere incidenze finanziarie significative per il finanziamento del bilancio, in particolare i progetti di natura immobiliare, quali la locazione o l’acquisto di edifici. Esso ne informa la Commissione.</p>\n</div>"], [10, "<div>\n<p class=\"oj-normal\">10.   Nel caso in cui un ramo dell'autorità di bilancio abbia comunicato l’intenzione di esprimere un parere, esso trasmette tale parere al consiglio di amministrazione entro un termine di sei settimane a decorrere dalla data di notifica del progetto.</p>\n</div>"]]}, "35": {"label": "Articolo 35", "heading": "Esecuzione del bilancio", "anchor": "art_35", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il direttore esecutivo è responsabile dell'esecuzione del bilancio dell'Ufficio di sostegno.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il direttore esecutivo trasmette ogni anno all’autorità di bilancio qualsiasi informazione rilevante in relazione ai risultati delle procedure di valutazione.</p>\n</div>"]]}, "36": {"label": "Articolo 36", "heading": "Rendicontazione e discarico", "anchor": "art_36", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Entro il 1<span class=\"oj-super\">o</span> marzo successivo a ciascun anno finanziario, il contabile dell'Ufficio di sostegno comunica al contabile della Commissione il rendiconto provvisorio, corredato della relazione sulla gestione finanziaria e di bilancio dell'esercizio chiuso. Il contabile della Commissione consolida il rendiconto provvisorio delle istituzioni e degli organismi decentrati ai sensi dell'articolo 128 del regolamento finanziario.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Entro il 31 marzo successivo a ciascun anno finanziario, il contabile della Commissione trasmette alla Corte dei conti il rendiconto provvisorio dell'Ufficio di sostegno corredato della relazione sulla gestione finanziaria e di bilancio dell'esercizio chiuso. La relazione sulla gestione finanziaria e di bilancio dell'esercizio chiuso è trasmessa anche al Parlamento europeo e al Consiglio.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Al ricevimento delle osservazioni formulate dalla Corte dei conti sul rendiconto provvisorio dell'Ufficio di sostegno, ai sensi dell'articolo 129 del regolamento finanziario il direttore esecutivo redige il rendiconto definitivo dell'Ufficio di sostegno, sotto la propria responsabilità, e lo trasmette al consiglio di amministrazione per un parere.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il consiglio d'amministrazione esprime un parere sul rendiconto definitivo dell'Ufficio di sostegno.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Entro il 1<span class=\"oj-super\">o</span> luglio successivo a ciascun anno finanziario, il direttore esecutivo trasmette il rendiconto definitivo corredato del parere del consiglio d'amministrazione al Parlamento europeo, al Consiglio, alla Commissione e alla Corte dei conti.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Il rendiconto definitivo è pubblicato.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Entro il 30 settembre, il direttore esecutivo invia alla Corte dei conti una risposta alle osservazioni di quest’ultima. Invia inoltre tale risposta al Consiglio di amministrazione.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   Il direttore esecutivo presenta al Parlamento europeo, su richiesta dello stesso e a norma dall'articolo 146, paragrafo 3, del regolamento finanziario, tutte le informazioni necessarie al corretto svolgimento della procedura di discarico per l'esercizio in causa.</p>\n</div>"], [9, "<div>\n<p class=\"oj-normal\">9.   Il Parlamento europeo, su raccomandazione del Consiglio che delibera a maggioranza qualificata, dà atto al direttore esecutivo, entro il 15 maggio dell'anno N + 2, dell'esecuzione del bilancio dell'esercizio N.</p>\n</div>"]]}, "37": {"label": "Articolo 37", "heading": "Regolamento finanziario", "anchor": "art_37", "frags": [[null, "<p class=\"oj-normal\">Il regolamento finanziario applicabile all'Ufficio di sostegno è adottato dal consiglio di amministrazione, previa consultazione della Commissione. Esso non si discosta dal regolamento (CE, Euratom) n. 2343/2002 della Commissione, del 19 novembre 2002, che reca regolamento finanziario quadro degli organismi di cui all'articolo 185 del regolamento (CE, Euratom) n. 1605/2002 del Consiglio che stabilisce il regolamento finanziario applicabile al bilancio generale delle Comunità europee (<span class=\"oj-super oj-note-tag\">11</span>), solo per esigenze specifiche di funzionamento dell’Ufficio di sostegno e previo accordo della Commissione.</p>"]]}, "38": {"label": "Articolo 38", "heading": "Personale", "anchor": "art_38", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Al personale dell'Ufficio di sostegno e al suo direttore esecutivo si applicano lo statuto dei funzionari dell'Unione europea e il regime applicabile agli altri agenti dell'Unione europea di cui al regolamento (CEE, Euratom, CECA) n. 259/68 (<span class=\"oj-super oj-note-tag\">12</span>) («lo statuto») e le norme adottate congiuntamente dalle istituzioni dell'Unione per l'applicazione di detto statuto e regime.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il consiglio di amministrazione, di concerto con la Commissione, adotta le necessarie disposizioni di esecuzione secondo le modalità di cui all’articolo 110 dello statuto.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Nei confronti del proprio personale, l’Ufficio di sostegno esercita i poteri conferiti all’autorità investita del potere di nomina dallo statuto e all'autorità abilitata a stipulare contratti dal regime applicabile agli altri agenti.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il consiglio d'amministrazione adotta disposizioni che consentano di ricorrere a esperti nazionali distaccati dagli Stati membri presso l'Ufficio di sostegno.</p>\n</div>"]]}, "39": {"label": "Articolo 39", "heading": "Privilegi e immunità", "anchor": "art_39", "frags": [[null, "<p class=\"oj-normal\">All'Ufficio di sostegno si applica il protocollo sui privilegi e sulle immunità dell'Unione europea.</p>"]]}, "40": {"label": "Articolo 40", "heading": "Status giuridico", "anchor": "art_40", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L’Ufficio di sostegno è un organo dell'Unione. Esso ha personalità giuridica.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'Ufficio di sostegno gode in tutti gli Stati membri della più ampia capacità giuridica riconosciuta alle persone giuridiche dalle legislazioni nazionali. Può in particolare acquisire o alienare beni mobili e immobili e stare in giudizio.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L’Ufficio di sostegno è rappresentato dal direttore esecutivo.</p>\n</div>"]]}, "41": {"label": "Articolo 41", "heading": "Regime linguistico", "anchor": "art_41", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   All’Ufficio di sostegno si applicano le disposizioni previste dal regolamento n. 1 del 15 aprile 1958 che stabilisce il regime linguistico della Comunità economica europea (<span class=\"oj-super oj-note-tag\">13</span>).</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Fatte salve le decisioni prese in base all'articolo 342 del TFUE, la relazione generale annuale sulle attività dell'Ufficio di sostegno e il programma di lavoro annuale di cui all'articolo 29, paragrafo 1, lettere c) ed f), sono redatti in tutte le lingue ufficiali delle istituzioni dell'Unione europea.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   I servizi di traduzione necessari per il funzionamento dell'Ufficio di sostegno sono forniti dal centro di traduzione degli organismi dell'Unione europea.</p>\n</div>"]]}, "42": {"label": "Articolo 42", "heading": "Accesso ai documenti", "anchor": "art_42", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Ai documenti in possesso dell'Ufficio di sostegno si applica il regolamento (CE) n. 1049/2001.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Entro sei mesi dalla data della sua prima riunione, il consiglio di amministrazione adotta le modalità di applicazione del regolamento (CE) n. 1049/2001.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Le decisioni adottate dall'Ufficio di sostegno ai sensi dell'articolo 8 del regolamento (CE) n. 1049/2001 possono costituire oggetto di denuncia presso il Mediatore o di un ricorso dinanzi alla Corte di giustizia dell'Unione europea, alle condizioni di cui, rispettivamente, agli articoli 228 e 263 del TFUE.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il trattamento di dati personali da parte dell'Ufficio di sostegno è soggetto al regolamento (CE) n. 45/2001.</p>\n</div>"]]}, "43": {"label": "Articolo 43", "heading": "Regime di sicurezza in materia di protezione delle informazioni classificate e delle informazioni sensibili non classificate", "anchor": "art_43", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Ufficio di sostegno applica i principi in materia di sicurezza di cui alla decisione 2001/844/CE, CECA, Euratom della Commissione, del 29 novembre 2001, che modifica il regolamento interno della Commissione (<span class=\"oj-super oj-note-tag\">14</span>), in particolare le disposizioni relative allo scambio, al trattamento e all'archiviazione delle informazioni classificate.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'Ufficio di sostegno applica altresì i principi di sicurezza relativi al trattamento delle informazioni sensibili non classificate adottati e applicati dalla Commissione.</p>\n</div>"]]}, "44": {"label": "Articolo 44", "heading": "Lotta antifrode", "anchor": "art_44", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Per la lotta alle frodi, alla corruzione e ad altre attività illecite, si applica senza restrizioni il regolamento (CE) n. 1073/1999.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'Ufficio di sostegno aderisce all'accordo interistituzionale del 25 maggio 1999 ed emana prontamente le opportune disposizioni applicabili a tutti i dipendenti dell'Ufficio di sostegno.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Le decisioni in materia di finanziamento, nonché gli accordi e gli strumenti di esecuzione che ne conseguono, prevedono esplicitamente la possibilità che la Corte dei conti e l’OLAF effettuino, se del caso, controlli in loco presso i beneficiari delle risorse dell’Ufficio di sostegno e gli agenti responsabili della loro allocazione.</p>\n</div>"]]}, "45": {"label": "Articolo 45", "heading": "Regime di responsabilità", "anchor": "art_45", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   La responsabilità contrattuale dell'Ufficio di sostegno è disciplinata dalla normativa applicabile al contratto di cui trattasi.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   La Corte di giustizia dell'Unione europea è competente a giudicare in virtù di clausole compromissorie contenute in un contratto concluso dall'Ufficio di sostegno.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   In materia di responsabilità extracontrattuale l'Ufficio di sostegno risarcisce, secondo i principi generali comuni agli ordinamenti degli Stati membri, i danni causati dai suoi servizi o dai suoi agenti nell’esercizio delle loro funzioni.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   La Corte di giustizia dell'Unione europea è competente a pronunciarsi in merito alle controversie relative al risarcimento dei danni di cui al paragrafo 3.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   La responsabilità individuale del personale verso l’Ufficio di sostegno è disciplinata dalle disposizioni dello statuto.</p>\n</div>"]]}, "46": {"label": "Articolo 46", "heading": "Valutazione e revisione", "anchor": "art_46", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Entro 19 giugno 2014, l'Ufficio di sostegno commissiona una valutazione, esterna e indipendente, dei propri risultati sulla base di un mandato conferito dal consiglio di amministrazione di concerto con la Commissione. Tale valutazione concerne l'impatto dell'Ufficio di sostegno sulla cooperazione pratica in materia di asilo e sul sistema europeo comune di asilo. La valutazione tiene debitamente conto dei progressi conseguiti, nell'ambito del suo mandato, in particolare valutando se sono necessarie misure supplementari per assicurare un'effettiva solidarietà e condivisione di responsabilità con gli Stati membri soggetti a una pressione particolare. Essa affronta in particolare l'eventuale necessità di modificare il mandato dell'Ufficio di sostegno, con le conseguenze finanziarie di tale modifica, ed esamina altresì l'adeguatezza della struttura di gestione all'adempimento dei compiti dell'Ufficio di sostegno. La valutazione tiene conto dei pareri delle parti interessate sia a livello dell'Unione sia a livello nazionale.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il consiglio di amministrazione, di concerto con la Commissione, decide le scadenze delle valutazioni future, tenendo conto dei risultati della valutazione di cui al paragrafo 1.</p>\n</div>"]]}, "47": {"label": "Articolo 47", "heading": "Controlli amministrativi", "anchor": "art_47", "frags": [[null, "<p class=\"oj-normal\">Le attività dell'Ufficio di sostegno sono sottoposte al controllo del Mediatore, ai sensi dell'articolo 228 del TFUE.</p>"]]}, "48": {"label": "Articolo 48", "heading": "Cooperazione con la Danimarca", "anchor": "art_48", "frags": [[null, "<p class=\"oj-normal\">L'Ufficio di sostegno agevola la cooperazione operativa con la Danimarca, incluso lo scambio di informazioni e di migliori prassi su questioni che rientrano nelle sue attività.</p>"]]}, "49": {"label": "Articolo 49", "heading": "Cooperazione con paesi terzi e associati", "anchor": "art_49", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Ufficio di sostegno è aperto alla partecipazione dell'Islanda, del Liechtenstein, della Norvegia e della Svizzera in veste di osservatori. Vengono presi accordi per specificare in particolare la natura, la portata e le modalità di partecipazione di tali paesi ai lavori dell'Ufficio di sostegno, comprese disposizioni relative alla partecipazione alle iniziative dell'Ufficio di sostegno, ai contributi finanziari e al personale. In materia di personale, tali accordi rispettano in ogni caso lo statuto.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Per le questioni che rientrano nelle sue attività, nella misura necessaria all'espletamento dei suoi compiti, in accordo con la Commissione e nell'ambito del suo mandato, l'Ufficio di sostegno agevola la cooperazione operativa fra gli Stati membri e i paesi terzi diversi da quelli di cui al paragrafo 1 nel quadro della politica dell'Unione in materia di relazioni esterne e può altresì cooperare con le autorità competenti di paesi terzi, su aspetti tecnici dei settori disciplinati dal presente regolamento, nell'ambito di accordi operativi conclusi con tali autorità, conformemente alle disposizioni pertinenti del TFUE.</p>\n</div>"]]}, "50": {"label": "Articolo 50", "heading": "Cooperazione con l'UNHCR", "anchor": "art_50", "frags": [[null, "<p class=\"oj-normal\">L'Ufficio di sostegno coopera con l'UNHCR nei settori disciplinati dal presente regolamento, nel quadro di accordi operativi conclusi con tale organizzazione. Per l'Ufficio di sostegno, il consiglio di amministrazione decide gli accordi operativi, incluse le implicazioni finanziarie.</p>"], [null, "<p class=\"oj-normal\">Il consiglio di amministrazione può inoltre decidere che l'Ufficio di sostegno può mettere a disposizioni risorse finanziarie per coprire spese dell'UNHCR per attività non previste negli accordi operativi. Tali risorse rientrano nell'ambito delle relazioni privilegiate di cooperazione fra l'Ufficio di sostegno e l'UNHCR, quali definite al presente articolo così come all'articolo 2, paragrafo 5, all'articolo 5, all'articolo 9, paragrafo 1, all'articolo 25, paragrafo 4, e all'articolo 32, paragrafo 2. Conformemente all'articolo 75 del regolamento (CE, Euratom) n. 2343/2002, si applicano le disposizioni pertinenti del regolamento finanziario nonché delle sue modalità di esecuzione.</p>"]]}, "51": {"label": "Articolo 51", "heading": "Forum consultivo", "anchor": "art_51", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Ufficio di sostegno mantiene uno stretto dialogo con le pertinenti organizzazioni della società civile e i relativi organismi competenti che operano nel settore della politica di asilo a livello locale, regionale, nazionale, europeo o internazionale e istituisce a tal fine un forum consultivo.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il forum consultivo costituisce un meccanismo di scambio di informazioni e di condivisione di conoscenze. Esso assicura uno stretto dialogo tra l’Ufficio di sostegno e le parti interessate.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il forum consultivo è aperto a tutte le pertinenti parti interessate di cui al paragrafo 1. L'Ufficio di sostegno si rivolge ai membri del forum consultivo in funzione delle esigenze specifiche riguardanti settori individuati come prioritari per l'attività dell'Ufficio di sostegno.</p>\n<p class=\"oj-normal\">L’UNHCR è membro di diritto del forum consultivo.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   L'Ufficio di sostegno invita il forum consultivo in particolare a:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">formulare proposte al consiglio di amministrazione sul programma di lavoro annuale da adottare a norma dell’articolo 29, paragrafo 1, lettera f);</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">fornire un riscontro al consiglio d'amministrazione e proporre il seguito da dare alla relazione annuale di cui all'articolo 29, paragrafo 1, lettera c), e alla relazione annuale sulla situazione riguardante l'asilo nell'Unione di cui all’articolo 12, paragrafo 1; e</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">comunicare al direttore esecutivo e al consiglio d'amministrazione i risultati e le raccomandazioni delle conferenze, dei seminari e delle riunioni pertinenti per i lavori dell'Ufficio di sostegno.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Il forum consultivo si riunisce almeno una volta all’anno.</p>\n</div>"]]}, "52": {"label": "Articolo 52", "heading": "Cooperazione con Frontex, FRA, altri organismi dell'Unione e con le organizzazioni internazionali", "anchor": "art_52", "frags": [[null, "<p class=\"oj-normal\">L'Ufficio di sostegno coopera con gli organismi dell'Unione che svolgono attività legate al suo settore di competenza, in particolare con Frontex e con FRA, così come con organizzazioni internazionali nei settori disciplinati dal presente regolamento, nell'ambito di accordi operativi conclusi con tali organismi conformemente alle disposizioni del TFUE e alle disposizioni relative alla competenza di tali organismi.</p>"], [null, "<p class=\"oj-normal\">La cooperazione consente di creare sinergie fra i diversi organismi interessati e di evitare duplicazioni nei lavori svolti nell'ambito dei loro mandati.</p>"]]}, "53": {"label": "Articolo 53", "heading": "Accordo di sede e condizioni operative", "anchor": "art_53", "frags": [[null, "<p class=\"oj-normal\">Le necessarie disposizioni relative all'insediamento dell'Ufficio di sostegno nello Stato membro ospitante e alle strutture che questo deve mettere a disposizione nonché le norme specifiche applicabili in tale Stato membro al direttore esecutivo dell'Ufficio di sostegno, ai membri del consiglio d'amministrazione, al personale dell'Ufficio di sostegno e ai familiari sono fissate in un accordo di sede concluso, previa approvazione del consiglio d'amministrazione, fra l'Ufficio di sostegno e lo Stato membro ospitante. Lo Stato membro ospitante garantisce le migliori condizioni possibili per il buon funzionamento dell'Ufficio di sostegno, offrendo anche una scolarizzazione multilingue e a orientamento europeo, e adeguati collegamenti di trasporto.</p>"]]}, "54": {"label": "Articolo 54", "heading": "Inizio delle attività dell'Ufficio di sostegno", "anchor": "art_54", "frags": [[null, "<p class=\"oj-normal\">L'Ufficio di sostegno diventa pienamente operativo entro 19 giugno 2011.</p>"], [null, "<p class=\"oj-normal\">La Commissione è responsabile dell'istituzione e del funzionamento iniziale dell'Ufficio di sostegno finché questo non abbia la capacità operativa di eseguire il proprio bilancio.</p>"], [null, "<p class=\"oj-normal\">A tale scopo,</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">—</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">fino a quando il direttore esecutivo non assumerà le proprie funzioni dopo la nomina da parte del consiglio d'amministrazione ai sensi dell'articolo 30, un funzionario della Commissione può farne le veci in qualità di direttore <span class=\"oj-italic\">ad interim</span> ed esercitare le funzioni assegnate al direttore esecutivo;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">—</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">funzionari della Commissione possono svolgere, sotto la responsabilità del direttore ad interim o del direttore esecutivo, i compiti assegnati all'Ufficio di sostegno.</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<p class=\"oj-normal\">Il direttore ad interim può autorizzare tutti i pagamenti coperti dagli stanziamenti previsti nel bilancio dell'Ufficio di sostegno, previa approvazione del consiglio d'amministrazione, e può concludere contratti, anche relativi al personale, in seguito all'adozione della tabella dell'organico.</p>"]]}, "55": {"label": "Articolo 55", "heading": "Entrata in vigore", "anchor": "art_55", "frags": [[null, "<p class=\"oj-normal\">Il presente regolamento entra in vigore il ventesimo giorno successivo alla pubblicazione nella <span class=\"oj-italic\">Gazzetta ufficiale dell’Unione europea</span>.</p>"]]}}, "recitals": {}};